const headers = $json.headers || {};
const raw = $json.body ?? $json.data ?? $json;
const body = typeof raw === 'string' ? (() => { try { return JSON.parse(raw); } catch (e) { return {}; } })() : (raw || {});
const message = String(body.chatInput ?? body.message ?? body.text ?? '').trim();
const source = String(body.source ?? 'stratosbot-site');
const channel = String(body.channel ?? 'website-demo');
const fromHeader = (headers['x-session-id'] || headers['X-Session-Id'] || '').toString().trim();
const rawClientId = body.sessionId ?? body.session_id ?? $json.sessionId ?? $json.session_id ?? (fromHeader !== '' ? fromHeader : null);
const clientId = rawClientId != null && String(rawClientId).trim() !== '' ? String(rawClientId).trim() : null;
const ip = (headers['x-forwarded-for'] || headers['x-real-ip'] || '').toString().split(',')[0].trim().replace(/[^a-zA-Z0-9.:]/g, '_') || 'n';
const ua = (headers['user-agent'] || '').toString().slice(0, 30).replace(/[^a-zA-Z0-9]/g, '_') || 'u';
const requestFingerprint = ip + '_' + ua;
const sessionId = clientId
  ? `${source}_${channel}_${clientId}`
  : `anon_${source}_${channel}_${requestFingerprint}_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
const clientSessionId = clientId || sessionId;
const leadRaw = body.lead ?? body.payload?.lead ?? body.raw?.lead ?? {};
const lead_name = (leadRaw?.name != null && String(leadRaw.name).trim() !== '') ? String(leadRaw.name).trim() : '';
const lead_phone = (leadRaw?.phone != null && String(leadRaw.phone).trim() !== '') ? String(leadRaw.phone).trim() : '';
const lead_email = (leadRaw?.email != null && String(leadRaw.email).trim() !== '') ? String(leadRaw.email).trim() : '';
return [{ json: { message, sessionId, clientSessionId, source, channel, lead_name, lead_phone, lead_email, raw: body } }];

const normalizar = $('Normalizar Entrada').first().json;
const hasError = !!($json.error || ($json.code && $json.code >= 400));
const output = $json.output ?? $json.reply ?? $json.text ?? '';
const fallbackOk = 'Recebi sua mensagem. Pode me dar mais detalhes para eu te ajudar melhor?';
const fallbackError = 'Desculpe, tive um problema ao processar agora. Pode repetir em um instante?';
const reply = String(hasError ? fallbackError : (output || fallbackOk));
const rawSession = $json.sessionId ?? normalizar?.sessionId;
const sessionId = (rawSession != null && String(rawSession).trim() !== '') ? String(rawSession).trim() : `anon_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
const clientSessionId = normalizar?.clientSessionId ?? sessionId;
const message = normalizar?.message ?? $json.message ?? '';
const source = normalizar?.source ?? $json.source ?? 'stratosbot-site';
const channel = normalizar?.channel ?? $json.channel ?? 'website-demo';
const lead_name = normalizar?.lead_name ?? '';
const lead_phone = normalizar?.lead_phone ?? '';
const lead_email = normalizar?.lead_email ?? '';
return [{ json: { reply, sessionId, clientSessionId, message, source, channel, lead_name, lead_phone, lead_email } }];

const formatar = $('Formatar Resposta').first().json;
// Este node agora roda a partir de "Buscar sessão"; usa o item atual para evitar pegar dado antigo de outra execução.
const existing = ($json && typeof $json === 'object' && Object.keys($json).length > 0) ? $json : null;
const existingConv = Array.isArray(existing?.conversation) ? existing.conversation : [];
const turn = { role: 'user', message: formatar.message, reply: formatar.reply, at: new Date().toISOString() };
const conversation = [...existingConv, turn].slice(-100);
const lead_name = (formatar.lead_name && String(formatar.lead_name).trim() !== '') ? String(formatar.lead_name).trim() : (existing?.lead_name ?? null);
const lead_phone = (formatar.lead_phone && String(formatar.lead_phone).trim() !== '') ? String(formatar.lead_phone).trim() : (existing?.lead_phone ?? null);
const lead_email = (formatar.lead_email && String(formatar.lead_email).trim() !== '') ? String(formatar.lead_email).trim() : (existing?.lead_email ?? null);
return [{ json: {
  sessionId: formatar.sessionId,
  conversation,
  message: formatar.message,
  reply: formatar.reply,
  source: formatar.source,
  channel: formatar.channel,
  lead_name,
  lead_phone,
  lead_email,
  updated_at: new Date().toISOString(),
  existingId: existing?.id ?? null
}}];
